import React, { useMemo, type JSX } from "react";
import IndicatorLineChart from "./IndicatorLineChart";
import { parseHeightPx } from "./klineUtil";
import {
  getJellyAnchorIndex,
  getJellyLiquidityComparisonWindow,
} from "../../../offline/mock_data/jellyevent";
import { useOptionalJellyMode } from "../../context/JellyModeContext";

export interface JellyLiquidityComparisonWidgetProps {
  height?: string;
  className?: string;
}

function formatDepth(value: number): string {
  if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(2)}M`;
  if (value >= 1_000) return `${(value / 1_000).toFixed(0)}k`;
  return value.toFixed(0);
}

function JellyLiquidityComparisonWidget({
  height,
  className = "",
}: JellyLiquidityComparisonWidgetProps): JSX.Element {
  const jellyCtx = useOptionalJellyMode();
  const frameIndex = jellyCtx?.frameIndex ?? getJellyAnchorIndex();

  const points = useMemo(
    () => getJellyLiquidityComparisonWindow(frameIndex),
    [frameIndex],
  );

  const latest = points.at(-1);

  const series = useMemo(
    () => [
      {
        id: "depth-hl",
        label: "HL depth",
        data: points.map((p) => ({ time: p.time, value: p.depthHL })),
        color: "#ef5350",
        priceScaleId: "left",
      },
      {
        id: "depth-morp",
        label: "Morp depth",
        data: points.map((p) => ({ time: p.time, value: p.depthMorp })),
        color: "#26a69a",
        priceScaleId: "left",
      },
      {
        id: "slippage-hl",
        label: "HL slippage",
        data: points.map((p) => ({ time: p.time, value: p.slippageHL })),
        color: "#ff8a65",
        priceScaleId: "right",
        lineStyle: 2 as const,
      },
      {
        id: "slippage-morp",
        label: "Morp slippage",
        data: points.map((p) => ({ time: p.time, value: p.slippageMorp })),
        color: "#4db6ac",
        priceScaleId: "right",
        lineStyle: 2 as const,
      },
    ],
    [points],
  );

  const statusText = latest
    ? `HL ${formatDepth(latest.depthHL)} · Morp ${formatDepth(latest.depthMorp)} · slip ${latest.slippageHL.toFixed(2)}% / ${latest.slippageMorp.toFixed(2)}%`
    : "Liquidity depth";

  return (
    <div
      className={`jelly-comparison-chart-widget ${className}`.trim()}
      style={{
        width: "100%",
        height: "100%",
        minHeight: parseHeightPx(height),
        display: "flex",
        flexDirection: "column",
      }}
    >
      <div
        style={{
          position: "absolute",
          zIndex: 9,
          bottom:"25px",
          padding: "0.25rem 0.5rem 0",
          fontSize: "0.65rem",
          color: "rgba(255,255,255,0.55)",
        }}
      >
        {statusText}
      </div>
      <IndicatorLineChart
        title="Liquidity depth · HL vs Morpheum"
        series={series}
        leftAxisLabel="Depth (USD)"
        rightAxisLabel="Slippage %"
        height={parseHeightPx(height) ?? 220}
        legend={[
          { label: "HL depth", color: "#ef5350" },
          { label: "Morp depth", color: "#26a69a" },
          { label: "HL slip", color: "#ff8a65", dashed: true },
          { label: "Morp slip", color: "#4db6ac", dashed: true },
        ]}
      />
    </div>
  );
}

export default JellyLiquidityComparisonWidget;
